INSERT INTO public.artworks (id, slug, title, medium, dimensions, price, status, description, image_url, is_featured, year, created_at, printify_matte_product_id, printify_framed_product_id, image_width, image_height, image_rotation) VALUES (22, 'the-warm-waking-cold', 'The Warm Waking Cold', 'Acrylic on Wood', '3'' × 3''', 100000, 'available', 'This piece explores the experience of waking into mania — and the shadow of depression that follows, haunting the self as an ever-present fear of return.', 'https://cdn.jsdelivr.net/gh/free-whiteboard-online/Free-Erasorio-Alternative-for-Collaborative-Design@c8bd91b79ea3ea9eb0d0edd9139854008d0d5766/uploads/2026-03-30T20-55-46-776Z-28sv8qptt.jpg', true, 2024, '2026-03-30 22:48:21.478178+00', '69dc1d9570e65284fd01b0ef', NULL, 1792, 2156, NULL);
INSERT INTO public.artworks (id, slug, title, medium, dimensions, price, status, description, image_url, is_featured, year, created_at, printify_matte_product_id, printify_framed_product_id, image_width, image_height, image_rotation) VALUES (23, 'hands-to-yourself', 'Hands to Yourself', 'Acrylic on Canvas', '3'' × 1.5''', 75000, 'available', 'This piece confronts the feeling of helplessness and grotesquery that comes in dreams about being sexually violated.', 'https://cdn.jsdelivr.net/gh/free-whiteboard-online/Free-Erasorio-Alternative-for-Collaborative-Design@6f1b614055b286df6030dd9bbc5400decb619c5c/uploads/2026-03-30T20-56-07-001Z-59ddwbthe.jpg', true, 2023, '2026-03-30 22:48:21.481232+00', '69dc1d98a6714c1fd5036834', NULL, 864, 1233, NULL);
INSERT INTO public.artworks (id, slug, title, medium, dimensions, price, status, description, image_url, is_featured, year, created_at, printify_matte_product_id, printify_framed_product_id, image_width, image_height, image_rotation) VALUES (21, 'grin-and-bear-it', 'Grin and Bear It', 'Acrylic on Canvas', '3'' × 1.5''', 75000, 'available', 'This piece captures the circus-like dance of mental awakening — the sensation of consciousness returning, almost blinding in its intensity, as the light of the world rushes back in.', 'https://cdn.jsdelivr.net/gh/free-whiteboard-online/Free-Erasorio-Alternative-for-Collaborative-Design@543b8056aee8e2e39560fee8533ae82d0f707a07/uploads/2026-03-30T20-55-07-996Z-co1m2osgt.jpg', true, 2024, '2026-03-30 22:48:21.473744+00', '69dc1db0e886ba00030808f5', NULL, 691, 1041, NULL);
