INSERT INTO public.artworks (id, slug, title, medium, dimensions, price, status, description, image_url, is_featured, year, created_at, printify_matte_product_id, printify_framed_product_id, image_width, image_height, image_rotation) VALUES (37, 'the-lights-too-bright-the-sound-too-loud', 'The Lights Too Bright, The Sound Too Loud', 'Oil and Ink on Canvas', '4'' by 4''', 150000, 'sold', NULL, 'https://cdn.jsdelivr.net/gh/free-whiteboard-online/Free-Erasorio-Alternative-for-Collaborative-Design@e968480b9bc4b54d5eeb8d46701f815c5cc7233a/uploads/2026-03-30T21-15-00-026Z-ywv7z8ljy.jpg', false, NULL, '2026-03-30 22:48:21.523643+00', '69dc1da8a6714c1fd5036836', NULL, 848, 856, NULL);
INSERT INTO public.artworks (id, slug, title, medium, dimensions, price, status, description, image_url, is_featured, year, created_at, printify_matte_product_id, printify_framed_product_id, image_width, image_height, image_rotation) VALUES (24, 'endure', 'Endure', 'Acrylic on Canvas', '4'' × 3.5''', 400000, 'sold', 'This work is rooted in the weight of the mind — and the world the mind creates for itself. Color, for me, is a form of confrontation; I work with it as a means of facing my mental illness directly, a practice of exposure therapy embedded in the creative process. Though heavy and emotional in nature, the piece carries an underlying message of perseverance and personal fortitude. It is among the works I am most proud of. There is a cosmic, otherworldly quality to it — one that emerged organically, almost beyond my own understanding of how it came to be.', 'https://cdn.jsdelivr.net/gh/free-whiteboard-online/Free-Erasorio-Alternative-for-Collaborative-Design@a06169277ae7c11ddf17d46271df1ceb7b85418d/uploads/2026-03-30T20-57-08-625Z-bt4s164un.png', true, 2024, '2026-03-30 22:48:21.483753+00', '69dc1dbae8f2cd193a0ec136', NULL, 1776, 2374, NULL);
